n10: 		addAuditPathChecker(c, entry, view, viewPath)
n11: 		origViewReadOnlyErr := view.getReadOnlyErr()

		// Mark the view as read-only until the mounting is complete and
		// ensure that it is reset after. This ensures that there will be no
		// writes during the construction of the backend.
n12: 		view.setReadOnlyErr(logical.ErrSetupReadOnly)
n13: 		c.postUnsealFuncs = append(c.postUnsealFuncs, func() {
